import java.io.*;
import java.util.*;

public class Main {
    private static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        Integer nextInt() throws IOException {
            int c;
            do {
                c = readByte();
                if (c == -1) return null;
            } while (c <= ' ');
            boolean neg = false;
            if (c == '-' ) { neg = true; c = readByte(); }
            int val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        Integer tObj = fs.nextInt();
        if (tObj == null) return;
        int T = tObj;
        StringBuilder out = new StringBuilder();
        for (int caseIdx = 0; caseIdx < T; caseIdx++) {
            int n = fs.nextInt();
            int m = fs.nextInt();
            int[] a = new int[n];
            int[] b = new int[m];
            for (int i = 0; i < n; i++) a[i] = fs.nextInt();
            for (int i = 0; i < m; i++) b[i] = fs.nextInt();
            Arrays.sort(a);
            Arrays.sort(b);
            int i = 0, j = 0;
            boolean first = true;
            while (i < n && j < m) {
                if (a[i] == b[j]) {
                    if (!first) out.append(' ');
                    out.append(a[i]);
                    first = false;
                    i++; j++;
                } else if (a[i] < b[j]) {
                    i++;
                } else {
                    j++;
                }
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

